import{_ as i,o as a,c as o,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Clawnet Refactor","description":"","frontmatter":{"summary":"Clawnet refactor: unify network protocol, roles, auth, approvals, identity","read_when":["Planning a unified network protocol for nodes + operator clients","Reworking approvals, pairing, TLS, and presence across devices"],"title":"Clawnet Refactor"},"headers":[],"relativePath":"refactor/clawnet.md","filePath":"refactor/clawnet.md","lastUpdated":1771906665000}'),r={name:"refactor/clawnet.md"};function t(n,e,s,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="clawnet-refactor-protocol-auth-unification" tabindex="-1"><a class="header-anchor" href="#clawnet-refactor-protocol-auth-unification">#</a> Clawnet refactor (protocol + auth unification)</h1><h2 id="hi" tabindex="-1"><a class="header-anchor" href="#hi">#</a> Hi</h2><p>Hi Peter — great direction; this unlocks simpler UX + stronger security.</p><h2 id="purpose" tabindex="-1"><a class="header-anchor" href="#purpose">#</a> Purpose</h2><p>Single, rigorous document for:</p><ul><li>Current state: protocols, flows, trust boundaries.</li><li>Pain points: approvals, multi‑hop routing, UI duplication.</li><li>Proposed new state: one protocol, scoped roles, unified auth/pairing, TLS pinning.</li><li>Identity model: stable IDs + cute slugs.</li><li>Migration plan, risks, open questions.</li></ul><h2 id="goals-from-discussion" tabindex="-1"><a class="header-anchor" href="#goals-from-discussion">#</a> Goals (from discussion)</h2><ul><li>One protocol for all clients (mac app, CLI, iOS, Android, headless node).</li><li>Every network participant authenticated + paired.</li><li>Role clarity: nodes vs operators.</li><li>Central approvals routed to where the user is.</li><li>TLS encryption + optional pinning for all remote traffic.</li><li>Minimal code duplication.</li><li>Single machine should appear once (no UI/node duplicate entry).</li></ul><h2 id="non‐goals-explicit" tabindex="-1"><a class="header-anchor" href="#non‐goals-explicit">#</a> Non‑goals (explicit)</h2><ul><li>Remove capability separation (still need least‑privilege).</li><li>Expose full gateway control plane without scope checks.</li><li>Make auth depend on human labels (slugs remain non‑security).</li></ul><hr><h1 id="current-state-as‐is" tabindex="-1"><a class="header-anchor" href="#current-state-as‐is">#</a> Current state (as‑is)</h1><h2 id="two-protocols" tabindex="-1"><a class="header-anchor" href="#two-protocols">#</a> Two protocols</h2><h3 id="_1-gateway-websocket-control-plane" tabindex="-1"><a class="header-anchor" href="#_1-gateway-websocket-control-plane">#</a> 1) Gateway WebSocket (control plane)</h3><ul><li>Full API surface: config, channels, models, sessions, agent runs, logs, nodes, etc.</li><li>Default bind: loopback. Remote access via SSH/Tailscale.</li><li>Auth: token/password via <code>connect</code>.</li><li>No TLS pinning (relies on loopback/tunnel).</li><li>Code: <ul><li><code>src/gateway/server/ws-connection/message-handler.ts</code></li><li><code>src/gateway/client.ts</code></li><li><code>docs/gateway/protocol.md</code></li></ul></li></ul><h3 id="_2-bridge-node-transport" tabindex="-1"><a class="header-anchor" href="#_2-bridge-node-transport">#</a> 2) Bridge (node transport)</h3><ul><li>Narrow allowlist surface, node identity + pairing.</li><li>JSONL over TCP; optional TLS + cert fingerprint pinning.</li><li>TLS advertises fingerprint in discovery TXT.</li><li>Code: <ul><li><code>src/infra/bridge/server/connection.ts</code></li><li><code>src/gateway/server-bridge.ts</code></li><li><code>src/node-host/bridge-client.ts</code></li><li><code>docs/gateway/bridge-protocol.md</code></li></ul></li></ul><h2 id="control-plane-clients-today" tabindex="-1"><a class="header-anchor" href="#control-plane-clients-today">#</a> Control plane clients today</h2><ul><li>CLI → Gateway WS via <code>callGateway</code> (<code>src/gateway/call.ts</code>).</li><li>macOS app UI → Gateway WS (<code>GatewayConnection</code>).</li><li>Web Control UI → Gateway WS.</li><li>ACP → Gateway WS.</li><li>Browser control uses its own HTTP control server.</li></ul><h2 id="nodes-today" tabindex="-1"><a class="header-anchor" href="#nodes-today">#</a> Nodes today</h2><ul><li>macOS app in node mode connects to Gateway bridge (<code>MacNodeBridgeSession</code>).</li><li>iOS/Android apps connect to Gateway bridge.</li><li>Pairing + per‑node token stored on gateway.</li></ul><h2 id="current-approval-flow-exec" tabindex="-1"><a class="header-anchor" href="#current-approval-flow-exec">#</a> Current approval flow (exec)</h2><ul><li>Agent uses <code>system.run</code> via Gateway.</li><li>Gateway invokes node over bridge.</li><li>Node runtime decides approval.</li><li>UI prompt shown by mac app (when node == mac app).</li><li>Node returns <code>invoke-res</code> to Gateway.</li><li>Multi‑hop, UI tied to node host.</li></ul><h2 id="presence-identity-today" tabindex="-1"><a class="header-anchor" href="#presence-identity-today">#</a> Presence + identity today</h2><ul><li>Gateway presence entries from WS clients.</li><li>Node presence entries from bridge.</li><li>mac app can show two entries for same machine (UI + node).</li><li>Node identity stored in pairing store; UI identity separate.</li></ul><hr><h1 id="problems-pain-points" tabindex="-1"><a class="header-anchor" href="#problems-pain-points">#</a> Problems / pain points</h1><ul><li>Two protocol stacks to maintain (WS + Bridge).</li><li>Approvals on remote nodes: prompt appears on node host, not where user is.</li><li>TLS pinning only exists for bridge; WS depends on SSH/Tailscale.</li><li>Identity duplication: same machine shows as multiple instances.</li><li>Ambiguous roles: UI + node + CLI capabilities not clearly separated.</li></ul><hr><h1 id="proposed-new-state-clawnet" tabindex="-1"><a class="header-anchor" href="#proposed-new-state-clawnet">#</a> Proposed new state (Clawnet)</h1><h2 id="one-protocol-two-roles" tabindex="-1"><a class="header-anchor" href="#one-protocol-two-roles">#</a> One protocol, two roles</h2><p>Single WS protocol with role + scope.</p><ul><li><strong>Role: node</strong> (capability host)</li><li><strong>Role: operator</strong> (control plane)</li><li>Optional <strong>scope</strong> for operator: <ul><li><code>operator.read</code> (status + viewing)</li><li><code>operator.write</code> (agent run, sends)</li><li><code>operator.admin</code> (config, channels, models)</li></ul></li></ul><h3 id="role-behaviors" tabindex="-1"><a class="header-anchor" href="#role-behaviors">#</a> Role behaviors</h3><p><strong>Node</strong></p><ul><li>Can register capabilities (<code>caps</code>, <code>commands</code>, permissions).</li><li>Can receive <code>invoke</code> commands (<code>system.run</code>, <code>camera.*</code>, <code>canvas.*</code>, <code>screen.record</code>, etc).</li><li>Can send events: <code>voice.transcript</code>, <code>agent.request</code>, <code>chat.subscribe</code>.</li><li>Cannot call config/models/channels/sessions/agent control plane APIs.</li></ul><p><strong>Operator</strong></p><ul><li>Full control plane API, gated by scope.</li><li>Receives all approvals.</li><li>Does not directly execute OS actions; routes to nodes.</li></ul><h3 id="key-rule" tabindex="-1"><a class="header-anchor" href="#key-rule">#</a> Key rule</h3><p>Role is per‑connection, not per device. A device may open both roles, separately.</p><hr><h1 id="unified-authentication-pairing" tabindex="-1"><a class="header-anchor" href="#unified-authentication-pairing">#</a> Unified authentication + pairing</h1><h2 id="client-identity" tabindex="-1"><a class="header-anchor" href="#client-identity">#</a> Client identity</h2><p>Every client provides:</p><ul><li><code>deviceId</code> (stable, derived from device key).</li><li><code>displayName</code> (human name).</li><li><code>role</code> + <code>scope</code> + <code>caps</code> + <code>commands</code>.</li></ul><h2 id="pairing-flow-unified" tabindex="-1"><a class="header-anchor" href="#pairing-flow-unified">#</a> Pairing flow (unified)</h2><ul><li>Client connects unauthenticated.</li><li>Gateway creates a <strong>pairing request</strong> for that <code>deviceId</code>.</li><li>Operator receives prompt; approves/denies.</li><li>Gateway issues credentials bound to: <ul><li>device public key</li><li>role(s)</li><li>scope(s)</li><li>capabilities/commands</li></ul></li><li>Client persists token, reconnects authenticated.</li></ul><h2 id="device‐bound-auth-avoid-bearer-token-replay" tabindex="-1"><a class="header-anchor" href="#device‐bound-auth-avoid-bearer-token-replay">#</a> Device‑bound auth (avoid bearer token replay)</h2><p>Preferred: device keypairs.</p><ul><li>Device generates keypair once.</li><li><code>deviceId = fingerprint(publicKey)</code>.</li><li>Gateway sends nonce; device signs; gateway verifies.</li><li>Tokens are issued to a public key (proof‑of‑possession), not a string.</li></ul><p>Alternatives:</p><ul><li>mTLS (client certs): strongest, more ops complexity.</li><li>Short‑lived bearer tokens only as a temporary phase (rotate + revoke early).</li></ul><h2 id="silent-approval-ssh-heuristic" tabindex="-1"><a class="header-anchor" href="#silent-approval-ssh-heuristic">#</a> Silent approval (SSH heuristic)</h2><p>Define it precisely to avoid a weak link. Prefer one:</p><ul><li><strong>Local‑only</strong>: auto‑pair when client connects via loopback/Unix socket.</li><li><strong>Challenge via SSH</strong>: gateway issues nonce; client proves SSH by fetching it.</li><li><strong>Physical presence window</strong>: after a local approval on gateway host UI, allow auto‑pair for a short window (e.g. 10 minutes).</li></ul><p>Always log + record auto‑approvals.</p><hr><h1 id="tls-everywhere-dev-prod" tabindex="-1"><a class="header-anchor" href="#tls-everywhere-dev-prod">#</a> TLS everywhere (dev + prod)</h1><h2 id="reuse-existing-bridge-tls" tabindex="-1"><a class="header-anchor" href="#reuse-existing-bridge-tls">#</a> Reuse existing bridge TLS</h2><p>Use current TLS runtime + fingerprint pinning:</p><ul><li><code>src/infra/bridge/server/tls.ts</code></li><li>fingerprint verification logic in <code>src/node-host/bridge-client.ts</code></li></ul><h2 id="apply-to-ws" tabindex="-1"><a class="header-anchor" href="#apply-to-ws">#</a> Apply to WS</h2><ul><li>WS server supports TLS with same cert/key + fingerprint.</li><li>WS clients can pin fingerprint (optional).</li><li>Discovery advertises TLS + fingerprint for all endpoints. <ul><li>Discovery is locator hints only; never a trust anchor.</li></ul></li></ul><h2 id="why" tabindex="-1"><a class="header-anchor" href="#why">#</a> Why</h2><ul><li>Reduce reliance on SSH/Tailscale for confidentiality.</li><li>Make remote mobile connections safe by default.</li></ul><hr><h1 id="approvals-redesign-centralized" tabindex="-1"><a class="header-anchor" href="#approvals-redesign-centralized">#</a> Approvals redesign (centralized)</h1><h2 id="current" tabindex="-1"><a class="header-anchor" href="#current">#</a> Current</h2><p>Approval happens on node host (mac app node runtime). Prompt appears where node runs.</p><h2 id="proposed" tabindex="-1"><a class="header-anchor" href="#proposed">#</a> Proposed</h2><p>Approval is <strong>gateway‑hosted</strong>, UI delivered to operator clients.</p><h3 id="new-flow" tabindex="-1"><a class="header-anchor" href="#new-flow">#</a> New flow</h3><ol><li>Gateway receives <code>system.run</code> intent (agent).</li><li>Gateway creates approval record: <code>approval.requested</code>.</li><li>Operator UI(s) show prompt.</li><li>Approval decision sent to gateway: <code>approval.resolve</code>.</li><li>Gateway invokes node command if approved.</li><li>Node executes, returns <code>invoke-res</code>.</li></ol><h3 id="approval-semantics-hardening" tabindex="-1"><a class="header-anchor" href="#approval-semantics-hardening">#</a> Approval semantics (hardening)</h3><ul><li>Broadcast to all operators; only the active UI shows a modal (others get a toast).</li><li>First resolution wins; gateway rejects subsequent resolves as already settled.</li><li>Default timeout: deny after N seconds (e.g. 60s), log reason.</li><li>Resolution requires <code>operator.approvals</code> scope.</li></ul><h2 id="benefits" tabindex="-1"><a class="header-anchor" href="#benefits">#</a> Benefits</h2><ul><li>Prompt appears where user is (mac/phone).</li><li>Consistent approvals for remote nodes.</li><li>Node runtime stays headless; no UI dependency.</li></ul><hr><h1 id="role-clarity-examples" tabindex="-1"><a class="header-anchor" href="#role-clarity-examples">#</a> Role clarity examples</h1><h2 id="iphone-app" tabindex="-1"><a class="header-anchor" href="#iphone-app">#</a> iPhone app</h2><ul><li><strong>Node role</strong> for: mic, camera, voice chat, location, push‑to‑talk.</li><li>Optional <strong>operator.read</strong> for status and chat view.</li><li>Optional <strong>operator.write/admin</strong> only when explicitly enabled.</li></ul><h2 id="macos-app" tabindex="-1"><a class="header-anchor" href="#macos-app">#</a> macOS app</h2><ul><li>Operator role by default (control UI).</li><li>Node role when “Mac node” enabled (system.run, screen, camera).</li><li>Same deviceId for both connections → merged UI entry.</li></ul><h2 id="cli" tabindex="-1"><a class="header-anchor" href="#cli">#</a> CLI</h2><ul><li>Operator role always.</li><li>Scope derived by subcommand: <ul><li><code>status</code>, <code>logs</code> → read</li><li><code>agent</code>, <code>message</code> → write</li><li><code>config</code>, <code>channels</code> → admin</li><li>approvals + pairing → <code>operator.approvals</code> / <code>operator.pairing</code></li></ul></li></ul><hr><h1 id="identity-slugs" tabindex="-1"><a class="header-anchor" href="#identity-slugs">#</a> Identity + slugs</h1><h2 id="stable-id" tabindex="-1"><a class="header-anchor" href="#stable-id">#</a> Stable ID</h2><p>Required for auth; never changes. Preferred:</p><ul><li>Keypair fingerprint (public key hash).</li></ul><h2 id="cute-slug-lobster‐themed" tabindex="-1"><a class="header-anchor" href="#cute-slug-lobster‐themed">#</a> Cute slug (lobster‑themed)</h2><p>Human label only.</p><ul><li>Example: <code>scarlet-claw</code>, <code>saltwave</code>, <code>mantis-pinch</code>.</li><li>Stored in gateway registry, editable.</li><li>Collision handling: <code>-2</code>, <code>-3</code>.</li></ul><h2 id="ui-grouping" tabindex="-1"><a class="header-anchor" href="#ui-grouping">#</a> UI grouping</h2><p>Same <code>deviceId</code> across roles → single “Instance” row:</p><ul><li>Badge: <code>operator</code>, <code>node</code>.</li><li>Shows capabilities + last seen.</li></ul><hr><h1 id="migration-strategy" tabindex="-1"><a class="header-anchor" href="#migration-strategy">#</a> Migration strategy</h1><h2 id="phase-0-document-align" tabindex="-1"><a class="header-anchor" href="#phase-0-document-align">#</a> Phase 0: Document + align</h2><ul><li>Publish this doc.</li><li>Inventory all protocol calls + approval flows.</li></ul><h2 id="phase-1-add-roles-scopes-to-ws" tabindex="-1"><a class="header-anchor" href="#phase-1-add-roles-scopes-to-ws">#</a> Phase 1: Add roles/scopes to WS</h2><ul><li>Extend <code>connect</code> params with <code>role</code>, <code>scope</code>, <code>deviceId</code>.</li><li>Add allowlist gating for node role.</li></ul><h2 id="phase-2-bridge-compatibility" tabindex="-1"><a class="header-anchor" href="#phase-2-bridge-compatibility">#</a> Phase 2: Bridge compatibility</h2><ul><li>Keep bridge running.</li><li>Add WS node support in parallel.</li><li>Gate features behind config flag.</li></ul><h2 id="phase-3-central-approvals" tabindex="-1"><a class="header-anchor" href="#phase-3-central-approvals">#</a> Phase 3: Central approvals</h2><ul><li>Add approval request + resolve events in WS.</li><li>Update mac app UI to prompt + respond.</li><li>Node runtime stops prompting UI.</li></ul><h2 id="phase-4-tls-unification" tabindex="-1"><a class="header-anchor" href="#phase-4-tls-unification">#</a> Phase 4: TLS unification</h2><ul><li>Add TLS config for WS using bridge TLS runtime.</li><li>Add pinning to clients.</li></ul><h2 id="phase-5-deprecate-bridge" tabindex="-1"><a class="header-anchor" href="#phase-5-deprecate-bridge">#</a> Phase 5: Deprecate bridge</h2><ul><li>Migrate iOS/Android/mac node to WS.</li><li>Keep bridge as fallback; remove once stable.</li></ul><h2 id="phase-6-device‐bound-auth" tabindex="-1"><a class="header-anchor" href="#phase-6-device‐bound-auth">#</a> Phase 6: Device‑bound auth</h2><ul><li>Require key‑based identity for all non‑local connections.</li><li>Add revocation + rotation UI.</li></ul><hr><h1 id="security-notes" tabindex="-1"><a class="header-anchor" href="#security-notes">#</a> Security notes</h1><ul><li>Role/allowlist enforced at gateway boundary.</li><li>No client gets “full” API without operator scope.</li><li>Pairing required for <em>all</em> connections.</li><li>TLS + pinning reduces MITM risk for mobile.</li><li>SSH silent approval is a convenience; still recorded + revocable.</li><li>Discovery is never a trust anchor.</li><li>Capability claims are verified against server allowlists by platform/type.</li></ul><h1 id="streaming-large-payloads-node-media" tabindex="-1"><a class="header-anchor" href="#streaming-large-payloads-node-media">#</a> Streaming + large payloads (node media)</h1><p>WS control plane is fine for small messages, but nodes also do:</p><ul><li>camera clips</li><li>screen recordings</li><li>audio streams</li></ul><p>Options:</p><ol><li>WS binary frames + chunking + backpressure rules.</li><li>Separate streaming endpoint (still TLS + auth).</li><li>Keep bridge longer for media‑heavy commands, migrate last.</li></ol><p>Pick one before implementation to avoid drift.</p><h1 id="capability-command-policy" tabindex="-1"><a class="header-anchor" href="#capability-command-policy">#</a> Capability + command policy</h1><ul><li>Node‑reported caps/commands are treated as <strong>claims</strong>.</li><li>Gateway enforces per‑platform allowlists.</li><li>Any new command requires operator approval or explicit allowlist change.</li><li>Audit changes with timestamps.</li></ul><h1 id="audit-rate-limiting" tabindex="-1"><a class="header-anchor" href="#audit-rate-limiting">#</a> Audit + rate limiting</h1><ul><li>Log: pairing requests, approvals/denials, token issuance/rotation/revocation.</li><li>Rate‑limit pairing spam and approval prompts.</li></ul><h1 id="protocol-hygiene" tabindex="-1"><a class="header-anchor" href="#protocol-hygiene">#</a> Protocol hygiene</h1><ul><li>Explicit protocol version + error codes.</li><li>Reconnect rules + heartbeat policy.</li><li>Presence TTL and last‑seen semantics.</li></ul><hr><h1 id="open-questions" tabindex="-1"><a class="header-anchor" href="#open-questions">#</a> Open questions</h1><ol><li><p>Single device running both roles: token model</p><ul><li>Recommend separate tokens per role (node vs operator).</li><li>Same deviceId; different scopes; clearer revocation.</li></ul></li><li><p>Operator scope granularity</p><ul><li>read/write/admin + approvals + pairing (minimum viable).</li><li>Consider per‑feature scopes later.</li></ul></li><li><p>Token rotation + revocation UX</p><ul><li>Auto‑rotate on role change.</li><li>UI to revoke by deviceId + role.</li></ul></li><li><p>Discovery</p><ul><li>Extend current Bonjour TXT to include WS TLS fingerprint + role hints.</li><li>Treat as locator hints only.</li></ul></li><li><p>Cross‑network approval</p><ul><li>Broadcast to all operator clients; active UI shows modal.</li><li>First response wins; gateway enforces atomicity.</li></ul></li></ol><hr><h1 id="summary-tl-dr" tabindex="-1"><a class="header-anchor" href="#summary-tl-dr">#</a> Summary (TL;DR)</h1><ul><li>Today: WS control plane + Bridge node transport.</li><li>Pain: approvals + duplication + two stacks.</li><li>Proposal: one WS protocol with explicit roles + scopes, unified pairing + TLS pinning, gateway‑hosted approvals, stable device IDs + cute slugs.</li><li>Outcome: simpler UX, stronger security, less duplication, better mobile routing.</li></ul>',133)])])}const g=i(r,[["render",t]]);export{u as __pageData,g as default};
